function checkAnswer(answer) {
    // 1. 将字符串按行分割成数组 (同时兼容 Windows 的 \r\n 和 Unix 的 \n)
    const lines = answer.split(/\r?\n/);
    // 如果行数不是 3 行，直接返回 false
    if (lines.length !== 3) {
        return false;
    }
    const line1 = lines[0];
    const line2 = lines[1];
    const line3 = lines[2];
    // 2. 检查第一行是否为 11 个字 (字符长度)
    if (line1.length !== 11) {
        return false;
    }
    // 3. 检查第三行是否为第二行的逐字逆序
    // 将 line2 转为数组 -> 反转数组 -> 转回字符串
    const reversedLine2 = line2.split('').reverse().join('');
    return line3 === reversedLine2;
}
